export function getModulo(id: string): Modulo | undefined {
  return modulos.find((m) => m.id === id);
}

export function getEscenario(moduloId: string, escenarioId: string): Escenario | undefined {
  const modulo = getModulo(moduloId);
  return modulo?.escenarios.find((e) => e.id === escenarioId);
}